class Solution:
    def findMaximizedCapital(self, k, w, profits, capital):
        projects = list(zip(capital, profits))
        for _ in range(k):
            best = -1
            best_idx = -1
            for i, (c, p) in enumerate(projects):
                if c <= w and p > best:
                    best = p
                    best_idx = i
            if best_idx == -1:
                break
            w += projects[best_idx][1]
            projects.pop(best_idx)
        return w

